@startuml
!theme base

package "auto" as auto {
  package "entity" as entity {
    class "«entity» AutoData" as AutoData {
      +_id?: string
      +__v?: number
      +createdAt?: number
      +updatedAt?: number
      +modell: string
      +klimabilanz?: number
      +typ?: AutoTyp
      +marke: Marke
      +preis: number
      +rabatt?: number
      +lieferbar?: boolean
      +datum?: Date
      +modellNr: string
      +homepage?: string
      +spezifikationen?: Array<string>
      +herstellungsorte: any
    }

    class "Marke" as Marke {
      [E]
      BMW
      AUDI
    }

    class "AutoTyp" as AutoTyp {
      [E]
      LIMOUSINE
      COUPE
    }

    class "AutoModel" as AutoModel
    class "validateAuto()" as validateAuto

    AutoData --> Marke
    AutoData --> AutoTyp
    AutoModel --> validateAuto
  }

  package "mongoose" as mongoose {
    class "Schema" as Schema {
      [C]
    }

    class "model()" as model
  }

  AutoModel --> Schema
  AutoModel --> model
}

@enduml
